/**
 * Template: provider span-config file
 */
import type { ProviderYaml } from './provider-yaml.types.js';

export function renderSpanConfig(cfg: ProviderYaml): string {
  const key = cfg.name.toUpperCase().replace(/-/g, '_');
  const sys = cfg.spans.system;
  const prefixes = cfg.spans.modelPrefixes
    .map((p) => `  '${p}',`)
    .join('\n');

  return `/**
 * @generated by @flusk/cli — provider generator
 * ${cfg.displayName} span detection config
 */

export const ${key}_SYSTEM_VALUES = [
  '${sys}',
];

export const ${key}_MODEL_PREFIXES = [
${prefixes}
];
`;
}
